select * from energy_report_daily_meter where report_date = #{reportDate} and generate_type != 2 and account_id in
#{accountId}
order by account_id asc, meter_id asc

select
    account_id as accountId,
    count(distinct meter_id) as meterCount
from energy_report_daily_meter
where report_date >= #{startDate}
  and report_date <= #{endDate}
  and account_id in

    #{accountId}

group by account_id
order by account_id asc

select *
from energy_report_daily_meter
where account_id = #{accountId}
  and report_date >= #{startDate}
  and report_date <= #{endDate}
order by meter_id asc, report_date asc
